import{_ as a,o as d,c as e,a0 as o}from"./chunks/framework.AQcSKqPn.js";const u=JSON.parse('{"title":"RedFox API — 小红书热门数据接口","description":"","frontmatter":{"type":"concept","title":"RedFox API — 小红书热门数据接口","tags":["redfox","xiaohongshu","api","trending","social-media"],"related":["ai-daily-news-digest"],"created":"2026-07-11T00:00:00.000Z","updated":"2026-07-11T00:00:00.000Z","date":"2026-07-11T00:00:00.000Z"},"headers":[],"relativePath":"concepts/redfox-api.md","filePath":"concepts/redfox-api.md","lastUpdated":1784599564000}'),i={name:"concepts/redfox-api.md"};function r(s,t,n,l,h,c){return d(),e("div",null,[...t[0]||(t[0]=[o(`<h1 id="redfox-api-—-小红书热门数据接口" tabindex="-1">RedFox API — 小红书热门数据接口 <a class="header-anchor" href="#redfox-api-—-小红书热门数据接口" aria-label="Permalink to &quot;RedFox API — 小红书热门数据接口&quot;">​</a></h1><ul><li><strong>发布日期</strong>: 2026年07月11日</li></ul><blockquote><p>CLI 脚本位于 <code>~/.hermes/scripts/redfox_api.py</code></p></blockquote><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>RedFox API 提供小红书（Xiaohongshu/RED）平台的爆款笔记和全网热搜关键词数据。与 AI Daily News Digest 结合使用，可生成包含全球 AI 新闻和中国社交媒体趋势的综合日报。</p><h2 id="_1-小红书爆款笔记-trending" tabindex="-1">1. 小红书爆款笔记 (Trending) <a class="header-anchor" href="#_1-小红书爆款笔记-trending" aria-label="Permalink to &quot;1. 小红书爆款笔记 (Trending)&quot;">​</a></h2><h3 id="cli" tabindex="-1">CLI <a class="header-anchor" href="#cli" aria-label="Permalink to &quot;CLI&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.hermes/scripts/redfox_api.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> trending</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> YYYY-MM-DD</span></span></code></pre></div><h3 id="响应结构" tabindex="-1">响应结构 <a class="header-anchor" href="#响应结构" aria-label="Permalink to &quot;响应结构&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>title</code></td><td>string</td><td>笔记标题（可能为空）</td></tr><tr><td><code>desc</code></td><td>string</td><td>笔记正文，含 #标签</td></tr><tr><td><code>userName</code></td><td>string</td><td>作者昵称</td></tr><tr><td><code>fans</code></td><td>string</td><td>粉丝数（如 <code>&quot;10w+&quot;</code>, <code>&quot;474&quot;</code>）</td></tr><tr><td><code>publicTime</code></td><td>string</td><td>发布时间</td></tr><tr><td><code>photoJumpUrl</code></td><td>string</td><td>笔记 URL</td></tr><tr><td><code>coverUrl</code></td><td>string</td><td>封面图 URL</td></tr><tr><td><code>anaAdd.addLikeCount</code></td><td>string</td><td>新增点赞</td></tr><tr><td><code>anaAdd.addCommentCount</code></td><td>string</td><td>新增评论</td></tr><tr><td><code>anaAdd.addCollectedCunt</code></td><td>string</td><td>新增收藏</td></tr><tr><td><code>anaAdd.addShareCount</code></td><td>string</td><td>新增分享</td></tr><tr><td><code>anaAdd.addInteractiveount</code></td><td>string</td><td><strong>新增互动总量（用于排序）</strong></td></tr></tbody></table><h3 id="排序与过滤" tabindex="-1">排序与过滤 <a class="header-anchor" href="#排序与过滤" aria-label="Permalink to &quot;排序与过滤&quot;">​</a></h3><ul><li>按 <code>addInteractiveount</code> 降序排列</li><li>粉丝数 &lt; 1000 标记为 <strong>低粉爆款</strong>🔥，代表高自然传播力</li></ul><h3 id="日期规则" tabindex="-1">日期规则 <a class="header-anchor" href="#日期规则" aria-label="Permalink to &quot;日期规则&quot;">​</a></h3><ul><li>北京时间 ≥ 19:00 → 使用<strong>昨日</strong>数据</li><li>北京时间 &lt; 19:00 → 使用<strong>前日</strong>数据</li></ul><p>原因是当日爆款数据仍在积累中。</p><h2 id="_2-全网热搜关键词-hot-keywords" tabindex="-1">2. 全网热搜关键词 (Hot Keywords) <a class="header-anchor" href="#_2-全网热搜关键词-hot-keywords" aria-label="Permalink to &quot;2. 全网热搜关键词 (Hot Keywords)&quot;">​</a></h2><h3 id="cli-1" tabindex="-1">CLI <a class="header-anchor" href="#cli-1" aria-label="Permalink to &quot;CLI&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.hermes/scripts/redfox_api.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hot_keywords</span></span></code></pre></div><h3 id="响应结构-1" tabindex="-1">响应结构 <a class="header-anchor" href="#响应结构-1" aria-label="Permalink to &quot;响应结构&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>keyword</code></td><td>string</td><td>热搜关键词</td></tr><tr><td><code>plats</code></td><td>array</td><td>热门平台列表（如 <code>[&quot;小红书&quot;, &quot;B站&quot;, &quot;头条&quot;, &quot;抖音&quot;, &quot;微博&quot;, &quot;百度&quot;, &quot;知乎&quot;, &quot;快手&quot;]</code>）</td></tr><tr><td><code>hotSpotList</code></td><td>array</td><td>各平台热搜详情（可能为空）</td></tr></tbody></table><h3 id="展示逻辑" tabindex="-1">展示逻辑 <a class="header-anchor" href="#展示逻辑" aria-label="Permalink to &quot;展示逻辑&quot;">​</a></h3><ul><li>按平台数量排序（平台越多越热门）</li><li>覆盖度分组：⭐⭐⭐⭐⭐（7-8 平台）、⭐⭐⭐⭐（5-6）、⭐⭐⭐（3-4）、⭐⭐（1-2）</li></ul><h2 id="_3-综合日报集成" tabindex="-1">3. 综合日报集成 <a class="header-anchor" href="#_3-综合日报集成" aria-label="Permalink to &quot;3. 综合日报集成&quot;">​</a></h2><p>结合 AI HOT + RedFox 的综合日报格式：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>📰 AI 行业日报       ← from AI HOT（或 QbitAI 回退）</span></span>
<span class="line"><span>📊 小红书今日爆款 TOP 10 ← from RedFox trending API</span></span>
<span class="line"><span>🔥 全网热搜关键词      ← from RedFox hot_keywords API</span></span></code></pre></div><p>小红书爆款格式化为 Markdown 表格：</p><table tabindex="0"><thead><tr><th>#</th><th>标题</th><th>作者(粉丝)</th><th>👍 点赞</th><th>💬 评论</th><th>⭐ 收藏</th><th>🔄 分享</th><th>互动总量</th></tr></thead></table><h2 id="安全性" tabindex="-1">安全性 <a class="header-anchor" href="#安全性" aria-label="Permalink to &quot;安全性&quot;">​</a></h2><p>安全扫描器拦截 <code>curl | python3</code> 管道，推荐：</p><ol><li>使用 Python <code>urllib.request</code> 替代 curl</li><li>先保存 curl 输出到文件，再读取处理</li></ol>`,30)])])}const b=a(i,[["render",r]]);export{u as __pageData,b as default};
